const Web3 = require("web3");
const EthereumTx = require('ethereumjs-tx').Transaction;

const web3 = new Web3("https://mainnet.infura.io/your_infura_project_id");
const myAddress = "0xYourEthereumAddress";
const privateKey = Buffer.from("your_private_key", "hex");

const destinationAddress = "0xDestinationAddress";

// send ETH
async function sendETH() {
    const txCount = await web3.eth.getTransactionCount(myAddress);
    const txObject = {
        nonce: web3.utils.toHex(txCount),
        to: destinationAddress,
        value: web3.utils.toHex(web3.utils.toWei("0.1", "ether")),
        gasLimit: web3.utils.toHex(21000),
        gasPrice: web3.utils.toHex(web3.utils.toWei("10", "gwei"))
    };

    const tx = new EthereumTx(txObject, {chain:'mainnet'});
    tx.sign(privateKey);

    const serializedTx = tx.serialize();
    const raw = '0x' + serializedTx.toString('hex');

    const transaction = await web3.eth.sendSignedTransaction(raw);
    console.log(`Transaction hash: ${transaction.transactionHash}`);
}

